# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;
using System;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int maxHealth = 100;
    public int currency = 0;
    public int attackPower = 10;
    public int defense = 5;
    public int level = 1;
    
    public void TakeDamage(int damage)
    {
        int actualDamage = Mathf.Max(0, damage - defense);
        health -= actualDamage;
        
        if (health <= 0)
        {
            health = 0;
            Die();
        }
        
        Debug.Log("Player took " + actualDamage + " damage. Health: " + health);
    }
    
    public void Heal(int amount)
    {
        health += amount;
        if (health > maxHealth)
        {
            health = maxHealth;
        }
        Debug.Log("Player healed " + amount + ". Health: " + health);
    }
    
    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Currency added: " + amount + ". Total: " + currency);
    }
    
    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            Debug.Log("Currency spent: " + amount + ". Remaining: " + currency);
            return true;
        }
        Debug.Log("Not enough currency!");
        return false;
    }
    
    public int CalculateDamageToEnemy(int baseDamage)
    {
        return baseDamage + attackPower + (level * 2);
    }
    
    public void LevelUp()
    {
        level++;
        maxHealth += 20;
        health = maxHealth;
        attackPower += 5;
        defense += 2;
        Debug.Log("Level up! Now level " + level);
    }
    
    void Die()
    {
        Debug.Log("Player died!");
    }
}

public class ShopSystem : MonoBehaviour
{
    public PlayerStats playerStats;
    
    public int healthPotionPrice = 50;
    public int attackUpgradePrice = 100;
    public int defenseUpgradePrice = 100;
    public int maxHealthUpgradePrice = 150;
    
    public int currencyPackSmallPrice = 100;
    public int currencyPackMediumPrice = 500;
    public int currencyPackLargePrice = 1000;
    
    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }
    
    public bool BuyHealthPotion()
    {
        if (playerStats.SpendCurrency(healthPotionPrice))
        {
            playerStats.Heal(50);
            Debug.Log("Bought health potion!");
            return true;
        }
        return false;
    }
    
    public bool BuyAttackUpgrade()
    {
        int price = CalculateUpgradePrice(attackUpgradePrice, playerStats.attackPower);
        
        if (playerStats.SpendCurrency(price))
        {
            playerStats.attackPower += 5;
            Debug.Log("Attack upgraded to " + playerStats.attackPower);
            return true;
        }
        return false;
    }
    
    public bool BuyDefenseUpgrade()
    {
        int price = CalculateUpgradePrice(defenseUpgradePrice, playerStats.defense);
        
        if (playerStats.SpendCurrency(price))
        {
            playerStats.defense += 3;
            Debug.Log("Defense upgraded to " + playerStats.defense);
            return true;
        }
        return false;
    }
    
    public bool BuyMaxHealthUpgrade()
    {
        int price = CalculateUpgradePrice(maxHealthUpgradePrice, playerStats.maxHealth / 10);
        
        if (playerStats.SpendCurrency(price))
        {
            playerStats.maxHealth += 25;
            playerStats.health += 25;
            Debug.Log("Max health upgraded to " + playerStats.maxHealth);
            return true;
        }
        return false;
    }
    
    public int CalculateUpgradePrice(int basePrice, int currentLevel)
    {
        return (int)(basePrice * Mathf.Pow(1.5f, currentLevel / 10));
    }
    
    public void PurchaseCurrencyPackSmall()
    {
        playerStats.AddCurrency(currencyPackSmallPrice);
        Debug.Log("Purchased small currency pack!");
    }
    
    public void PurchaseCurrencyPackMedium()
    {
        playerStats.AddCurrency(currencyPackMediumPrice);
        Debug.Log("Purchased medium currency pack!");
    }
    
    public void PurchaseCurrencyPackLarge()
    {
        playerStats.AddCurrency(currencyPackLargePrice);
        Debug.Log("Purchased large currency pack!");
    }
    
    public int GetAttackUpgradePrice()
    {
        return CalculateUpgradePrice(attackUpgradePrice, playerStats.attackPower);
    }
    
    public int GetDefenseUpgradePrice()
    {
        return CalculateUpgradePrice(defenseUpgradePrice, playerStats.defense);
    }
    
    public int GetMaxHealthUpgradePrice()
    {
        return CalculateUpgradePrice(maxHealthUpgradePrice, playerStats.maxHealth / 10);
    }
}

public class Enemy : MonoBehaviour
{
    public int health = 50;
    public int attackPower = 15;
    public int currencyReward = 25;
    
    public PlayerStats playerStats;
    
    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        
        if (health <= 0)
        {
            health = 0;
            Die();
        }
        
        Debug.Log("Enemy took " + damage + " damage. Health: " + health);
    }
    
    public void AttackPlayer()
    {
        int damage = CalculateDamage();
        playerStats.TakeDamage(damage);
    }
    
    public int CalculateDamage()
    {
        return attackPower + UnityEngine.Random.Range(-2, 3);
    }
    
    void Die()
    {
        Debug.Log("Enemy died! Rewarding currency: " + currencyReward);
        playerStats.AddCurrency(currencyReward);
        Destroy(gameObject);
    }
}

public class CombatManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public Enemy currentEnemy;
    
    void Start()
    {
        if (playerStats == null)
        {
            playerStats = FindObjectOfType<PlayerStats>();
        }
    }
    
    public void PlayerAttack()
    {
        if (currentEnemy != null)
        {
            int damage = playerStats.CalculateDamageToEnemy(10);
            currentEnemy.TakeDamage(damage);
        }
    }
    
    public void EnemyAttack()
    {
        if (currentEnemy != null)
        {
            currentEnemy.AttackPlayer();
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopSystem shopSystem;
    public CombatManager combatManager;
    
    void Start()
    {
        InitializeGame();
    }
    
    void InitializeGame()
    {
        if (playerStats == null)
        {
            GameObject playerObj = new GameObject("Player");
            playerStats = playerObj.AddComponent<PlayerStats>();
        }
        
        if (shopSystem == null)
        {
            GameObject shopObj = new GameObject("Shop");
            shopSystem = shopObj.AddComponent<ShopSystem>();
            shopSystem.playerStats = playerStats;
        }
        
        if (combatManager == null)
        {
            GameObject combatObj = new GameObject("Combat");
            combatManager = combatObj.AddComponent<CombatManager>();
            combatManager.playerStats = playerStats;
        }
        
        Debug.Log("Game initialized!");
    }
    
    public void SaveGame()
    {
        PlayerPrefs.SetInt("PlayerHealth", playerStats.health);
        PlayerPrefs.SetInt("PlayerMaxHealth", playerStats.maxHealth);
        PlayerPrefs.SetInt("PlayerCurrency", playerStats.currency);
        PlayerPrefs.SetInt("PlayerAttackPower", playerStats.attackPower);
        PlayerPrefs.SetInt("PlayerDefense", playerStats.defense);
        PlayerPrefs.SetInt("PlayerLevel", playerStats.level);
        PlayerPrefs.Save();
        Debug.Log("Game saved!");
    }
    
    public void LoadGame()
    {
        playerStats.health = PlayerPrefs.GetInt("PlayerHealth", 100);
        playerStats.maxHealth = PlayerPrefs.GetInt("PlayerMaxHealth", 100);
        playerStats.currency = PlayerPrefs.GetInt("PlayerCurrency", 0);
        playerStats.attackPower = PlayerPrefs.GetInt("PlayerAttackPower", 10);
        playerStats.defense = PlayerPrefs.GetInt("PlayerDefense", 5);
        playerStats.level = PlayerPrefs.GetInt("PlayerLevel", 1);
        Debug.Log("Game loaded!");
    }
}

